INSERT INTO `attractions` VALUES (1,128961,'강변스파랜드',12,1,6,'http://tong.visitkorea.or.kr/cms/resource/98/3401698_image2_1.JPG','http://tong.visitkorea.or.kr/cms/resource/98/3401698_image3_1.JPG',6,37.53482663050000000,127.09161161810000000,'','서울특별시 광진구 구의강변로 45','(구의동)','<a href=\"http://ispaland.co.kr/\"target=\"_blank\" title=\"새창:강변스파랜드\">http://ispaland.co.kr/</a>','강변스파랜드는 지하 1·2층, 9917.4m²(3,000평) 규모의 사우나를 즐길 수 있는 대규모 스파 시설이다. 재래식 불한증막과 찜질방, 사우나 등의 시설 이용과 함께 한 차원 높은 문화공간 체험이 가능한 곳이다. 지하 2층은 사우나, 지하 1층은 공용 찜질방이다. 세련된 인테리어와 유황 성분이 함유된 지하수 사우나 물은 매끄럽고 피부에도 좋다고 한다. 재래식 소나무장작불한증막, 넓은 공용 홀을 비롯하여 숯방, 소금방, 은피라미드방, 여성전용황토불가마, 황토방, 이글루체험방 등 다양한 찜질방과 온탕, 냉탕, 아쿠아워킹·마사지탕, 습식사우나, 건식사우나 등 각종 사우나시설을 즐길 수 있다. 부대시설로는 모임방, 어린이놀이방, 당구장, 탁구장, 대형게임장, 충전카페, 피부관리실이 있으며 한식당과 치킨·스낵코너에서 식사와 간단한 요깃거리를 해결할 수 있다.  강변스파랜드는 수도권 지하철 2호선 강변역 4번 출구에서 약 340m 정도 떨어진 위치에 있다.'),(2,2733966,'거리공원',12,1,7,'http://tong.visitkorea.or.kr/cms/resource/86/2780786_image2_1.png','http://tong.visitkorea.or.kr/cms/resource/86/2780786_image2_1.png',6,37.49979933520000000,126.89161415510000000,'','서울특별시 구로구 공원로 28','(구로동)','','구로구(九老區)는 옛날에 노인 9명이 오래도록 장수하였다는 전설로부터 유래된 지역이다. 서울특별시 구로구 구로동 106-5번지 가마 산길 거리공원오거리에서 구로구 구로동 3-55번지 신도림역에 이르는 보조 간 선급 가로를 거리공원길이라고 하는데, 구로 거리공원을 따라 이어진 길이라는 의미에서 거리공원길이라고 이름 붙였다. 구로거리공원은 봄에는 벚꽃으로 만개하고 가을에는 단풍으로 물들어 계절마다 아름다운 풍경을 즐길 수 있는 곳이다. 구로구 시민들의 산책 명소로 알려져 있다.'),(3,2756669,'화원자연휴양림',12,4,3,'http://tong.visitkorea.or.kr/cms/resource/52/2756852_image2_1.jpg','http://tong.visitkorea.or.kr/cms/resource/52/2756852_image2_1.jpg',6,35.77183001360000000,128.53675945390000000,'','대구광역시 달성군 화원읍 화원휴양림길 126','',NULL,NULL),(4,2718673,'휴파크 광산점',12,5,1,'http://tong.visitkorea.or.kr/cms/resource/00/3033500_image2_1.jpg','http://tong.visitkorea.or.kr/cms/resource/00/3033500_image3_1.jpg',6,35.19536346460000000,126.73039521250000000,'010-3275-3450','광주광역시 광산구 탑동길 345','(지산동)',NULL,NULL),(5,2684712,'흰여울문화마을',12,6,14,'','',6,35.07727584720000000,129.04637004450000000,'','부산광역시 영도구 흰여울길 379','',NULL,NU