CREATE TABLE `boards` (
  `id` int NOT NULL,
  `member_id` varchar(20) NOT NULL,
  `story_id` int DEFAULT NULL,
  `title` varchar(100) NOT NULL,
  `content` text,
  `hit` int DEFAULT '0',
